def prompt(self, name: str) -> str:
        """Load a prompt template by name (e.g. 'map', 'reduce', 'swap')."""
        if self.prompts_dir:
            path = self.prompts_dir / f"{name}.md"
        else:
            path = Path(__file__).parent / "prompts" / f"{name}.md"
        return path.read_text(encoding="utf-8")

